#include <iostream>
using namespace std;

class Stack {
    int arr[100];
    int top;
public:
    Stack() { top = -1; }
    void push(int x) { arr[++top] = x; }
    void pop() { if(top >= 0) top--; }
    int peek() { return arr[top]; }
};

#include <iostream>
using namespace std;

struct Node {
    int data;
    Node* next;
};

class Stack {
    Node* top;
public:
    Stack() { top = NULL; }
    void push(int x) {
        Node* temp = new Node();
        temp->data = x;
        temp->next = top;
        top = temp;
    }
    void pop() {
        if(top) {
            Node* temp = top;
            top = top->next;
            delete temp;
        }
    }
    int peek() { return top->data; }
};

#include <queue>
#include <iostream>
using namespace std;

class Stack {
    queue<int> q;
public:
    void push(int x) {
        int n = q.size();
        q.push(x);
        for(int i=0;i<n;i++) {
            q.push(q.front());
            q.pop();
        }
    }
    void pop() { q.pop(); }
    int top() { return q.front(); }
};

int main() {
    Stack s;
    s.push(10); s.push(20);
    cout << s.top(); // 20
}

#include <queue>
#include <iostream>
using namespace std;

class Stack {
    queue<int> q1, q2;
public:
    void push(int x) {
        q2.push(x);
        while(!q1.empty()) {
            q2.push(q1.front());
            q1.pop();
        }
        swap(q1, q2);
    }
    void pop() { q1.pop(); }
    int top() { return q1.front(); }
};

#include <stack>
#include <iostream>
using namespace std;

int eval(string exp) {
    stack<int> s;
    for(char c : exp) {
        if(isdigit(c)) s.push(c - '0');
        else {
            int b = s.top(); s.pop();
            int a = s.top(); s.pop();
            if(c == '+') s.push(a+b);
            if(c == '-') s.push(a-b);
        }
    }
    return s.top();
}
